_PROCESS_PRIORITIES = ("low", "below_normal", "normal", "above_normal", "high")


def _apply_process_priority(pid: int, priority: str) -> None:
    """Best-effort attempt to set the CPU priority of the process with
    the given pid. Any failure is silently ignored: priority is a
    resource-management nicety, not something that should ever cause
    the edit operation to fail.
    """
    if priority not in _PROCESS_PRIORITIES:
        return

    try:
        if WIN:
            import ctypes

            priority_classes = {
                "low": 0x00000040,  # IDLE_PRIORITY_CLASS
                "below_normal": 0x00004000,  # BELOW_NORMAL_PRIORITY_CLASS
                "normal": 0x00000020,  # NORMAL_PRIORITY_CLASS
                "above_normal": 0x00008000,  # ABOVE_NORMAL_PRIORITY_CLASS
                "high": 0x00000080,  # HIGH_PRIORITY_CLASS
            }
            # PROCESS_SET_INFORMATION
            handle = ctypes.windll.kernel32.OpenProcess(0x0200, False, pid)  # type: ignore[attr-defined]
            if handle:
                try:
                    ctypes.windll.kernel32.SetPriorityClass(  # type: ignore[attr-defined]
                        handle, priority_classes[priority]
                    )
                finally:
                    ctypes.windll.kernel32.CloseHandle(handle)  # type: ignore[attr-defined]
        else:
            niceness = {
                "low": 19,
                "below_normal": 10,
                "normal": 0,
                "above_normal": -5,
                "high": -10,
            }
            current = os.getpriority(os.PRIO_PROCESS, pid)
            os.setpriority(os.PRIO_PROCESS, pid, current + niceness[priority])
    except Exception:
        # Setting process priority is best-effort; never let it break
        # the edit operation, and never let unsupported platforms or
        # insufficient permissions raise.
        pass


